/****************************************************************
 *  CODE-3 – State engine (JS) - UPDATED WITH CONSENT FLOW
 *  Expecting: 2 merged items
 *     • Twilio webhook  → .json.body.WaId / Body / …
 *     • Postgres row    → .json.step_index / status / …
 ****************************************************************/

// ---------- 1. Identify which item is which ------------------
let twItem, dbItem;

for (const it of items) {
	if (it.json.body && it.json.body.SmsMessageSid) twItem = it.json;
	else if ('step_index' in it.json || 'user_id' in it.json) dbItem = it.json;
}
if (!twItem) throw new Error('Twilio payload missing after Merge');

const waBody = twItem.body;
const old    = dbItem || {};            // {} on very first message

// ---------- 2. Helpers ---------------------------------------
const userId   = old.user_id || waBody.WaId || waBody.From;
const text     = (waBody.Body || '').trim();
const numMedia = Number(waBody.NumMedia) || 0;
const mediaUrl = numMedia > 0 ? waBody.MediaUrl0 : null;

// ---------- 3. Working row (copy of DB row we can mutate) ----
const row = {
	user_id        : userId,
	first_name     : old.first_name      ?? null,
	dob            : old.dob             ?? null,
	tob            : old.tob             ?? null,
	birth_place    : old.birth_place     ?? null,
	dominant       : old.dominant        ?? null,
	marital_status : old.marital_status  ?? null,
	consent_given  : old.consent_given   ?? null,  // NEW - Phase 1
	consent_timestamp : old.consent_timestamp ?? null, // NEW - Phase 1
	right_url      : old.right_url       ?? null,
	left_url       : old.left_url        ?? null,
	step_index     : old.step_index      ?? 0,
	status         : old.status          ?? 'pending',
	just_consented : false,
};

// ---------- 4. Step definitions (NOW 10 STEPS) ---------------
const steps = [
	// 0 ▸ First name
	{
		prompt : 'What is your first name?',
		accept : v => v !== '',
		save   : v => { row.first_name = v; },
	},

	// 1 ▸ Date of birth
	{
		prompt : 'Your date of birth (YYYY-MM-DD or MM/DD/YYYY)?',
		accept : v =>
			/^\d{4}-\d{2}-\d{2}$/.test(v) ||            // ISO
			/^\d{1,2}\/\d{1,2}\/\d{4}$/.test(v),         // US
		save : v => {
			let y, m, d;
			if (v.includes('-')) [y, m, d] = v.split('-');
			else {
				const [mm, dd, yyyy] = v.split('/');
				y = yyyy; m = mm.padStart(2,'0'); d = dd.padStart(2,'0');
			}
			row.dob = `${y}-${m}-${d}`;
		},
		retry : 'Please enter DOB as YYYY-MM-DD (e.g. 2006-05-30) or MM/DD/YYYY (e.g. 05/30/2006)',
	},

	// 2 ▸ Time of birth
	{
		prompt : 'Your time of birth (HH:MM AM/PM)?',
		accept : v => /^\d{1,2}:\d{2}\s?(AM|PM)$/i.test(v),
		save   : v => { row.tob = v.toUpperCase(); },
		retry  : 'Please enter time like 5:30 AM',
	},

	// 3 ▸ Birth place
	{
		prompt : 'City and State (or Country) where you were born?\n\nExamples:\n• "Los Angeles, CA"\n• "London, UK"\n• "Rochester NY"',
		accept : v => {
			const trimmed = v.trim();
			// Must have comma OR pattern like "City ST" (2-letter state code)
			return trimmed.includes(',') || /\w+\s+[A-Z]{2}$/i.test(trimmed) || trimmed.split(/\s+/).length >= 2;
		},
		save   : v => { row.birth_place = v.trim(); },
		retry  : 'Please include both city AND state/country.\n\nExamples: "Miami, FL" or "Paris, France"',
	},

	// 4 ▸ Dominant hand
	{
		prompt : 'Which is your dominant hand? (R/L or Right/Left)',
		accept : v => /^(R|L|r|l|right|left)$/i.test(v),
		save   : v => { row.dominant = v[0].toUpperCase(); }, // store "R" or "L"
		retry  : 'Reply R or L (or Right / Left).',
	},

	// 5 ▸ Marital status
	{
		prompt : 'Current relationship status? (Single / Married / Divorced)',
		accept : v => /^(s|m|d|single|married|divorced)$/i.test(v),
		save   : v => {
			const c = v[0].toUpperCase();
			row.marital_status = c === 'S' ? 'Single' : c === 'M' ? 'Married' : 'Divorced';
		},
		retry  : 'Reply S, M, or D (Single / Married / Divorced).',
	},

	// 6 ▸ CONSENT (NEW - Phase 1)
	{
		prompt : `Received. Before we proceed to the architectural mapping of your palms, we are required by our internal compliance protocol to establish your formal consent.

Because your Life Chart involves the processing of biometric patterns and precise natal coordinates, we must ensure you have authorized this analysis.

This document contains our *AI Disclosure* (you are interacting with an advanced AI system, not a biological human), and our *Liability Shield* (this analysis is for self-reflective purposes and not a substitute for professional legal or medical advice).

Please review the full Terms of Service here:
https://yourwebsite.com/terms

*To authorize the Lead Analyst to open your file and process your biometric data, please reply with the word:*

*AGREE*`,
		accept : v => /^AGREE$/i.test(v.trim()),
		save   : v => { 
			row.consent_given = true;
			row.consent_timestamp = new Date().toISOString();
			row.just_consented = true;
		},
		retry  : 'You must type AGREE to continue. Reply STOP to cancel.',
	},

	// 7 ▸ Right-hand photo
	{
		prompt : '📸 Authorization confirmed. Please send a clear photo of your *RIGHT palm*.',
		accept : () => numMedia > 0,
		save   : () => { row.right_url = mediaUrl; },
		retry  : 'Need a photo of your RIGHT palm please.',
	},

	// 8 ▸ Left-hand photo
	{
		prompt : 'Excellent. Now your *LEFT palm* photo.',
		accept : () => numMedia > 0,
		save   : () => { row.left_url = mediaUrl; },
		retry  : 'Still need the LEFT-hand photo.',
	},
];

// ---------- 5. Auto-skip already-filled steps ----------------
while (
	row.step_index < steps.length &&
	[
		row.first_name,     // 0
		row.dob,            // 1
		row.tob,            // 2
		row.birth_place,    // 3
		row.dominant,       // 4
		row.marital_status, // 5
		row.consent_given === true ? true : null,  // 6 (consent)
		row.right_url,      // 7
		row.left_url,       // 8
	][row.step_index] !== null
) {
	row.step_index++;
}

// ---------- 6. Validate current answer -----------------------
let nextPrompt;
const cur = steps[row.step_index];

if (cur) {
	// Steps 0-7 use text input, steps 8-9 use media
	const ok = row.step_index < 7 ? cur.accept(text) : cur.accept();

	if (ok) {
		// Save only if not auto-skipped
		if (
			(row.step_index === 0 && row.first_name     === null) ||
			(row.step_index === 1 && row.dob           === null) ||
			(row.step_index === 2 && row.tob           === null) ||
			(row.step_index === 3 && row.birth_place   === null) ||
			(row.step_index === 4 && row.dominant      === null) ||
			(row.step_index === 5 && row.marital_status=== null) ||
			(row.step_index === 6 && row.consent_given !== true) ||
			(row.step_index === 7 && row.right_url     === null) ||
			(row.step_index === 8 && row.left_url      === null)
		) cur.save(text);
		row.step_index++;
	} else {
		nextPrompt = cur.retry || cur.prompt;
	}
}

// ---------- 7. Status & next question ------------------------
if (row.step_index >= steps.length) {
	row.status = 'complete';
	nextPrompt = null;
} else if (nextPrompt === undefined) {
	nextPrompt = steps[row.step_index].prompt;
}

// ---------- 8. Emit single output ----------------------------
return [
	{
		json: {
			...row,
			next_prompt: nextPrompt,
		},
	},
];

/****************************************************************
 * Parse Geocoding Results & Handle Errors                       *
 * Checks if Google Geocoding API returned valid results         *
 ****************************************************************/

const results = $json.results || [];
const userId = $('Postgres4').item.json.user_id;

if (results.length > 0 && results[0].geometry && results[0].geometry.location) {
  // Geocoding succeeded - extract coordinates
  const lat = results[0].geometry.location.lat;
  const lng = results[0].geometry.location.lng;

  return {
    json: {
      birth_lat: lat,
      birth_long: lng,
      user_id: userId,
      geocode_success: true,
      formatted_address: results[0].formatted_address || null
    }
  };
} else {
  // Geocoding failed or returned no results
  // Continue without coordinates (non-blocking)
  return {
    json: {
      birth_lat: null,
      birth_long: null,
      user_id: userId,
      geocode_success: false,
      formatted_address: null
    }
  };
}

