/************************************************************************
 *  SIGN TWILIO MEDIA LINKS                                             *
 *  Expects:                                                            *
 *      - this item   => Postgres row (selected earlier)                *
 *      - $('Switch1') => item that still holds right_url / left_url    *
 ************************************************************************/

const SID   = 'YOUR_TWILIO_ACCOUNT_SID';   // Twilio SID
const TOKEN = 'YOUR_TWILIO_AUTH_TOKEN';     // Twilio Auth-Token

// helper → turn `https://…` into `https://SID:TOKEN@…`
const sign = url =>
  url ? url.replace('https://', `https://${SID}:${TOKEN}@`) : null;

// 1) URLs that came from the Twilio / Switch branch
const tw   = $('Switch1').item;          // node name that has right_url / left_url
const rightUrl = sign(tw?.json.right_url);
const leftUrl  = sign(tw?.json.left_url);

// 2) keep everything the current item already had (row from Postgres)
return {
  json: {
    ...$json,               // id, first_name, step_index, …
    right_public: rightUrl, // now Vision-ready
    left_public:  leftUrl
  }
};

/*****************************************************************
*  Clean the HTML reading for WhatsApp                           *
*  Expects item.json.html  (your full e-mail body)               *
*  Returns an array of {to, body} items (<=1600 chars each)      *
*****************************************************************/

const html  = $input.first().json.message.content || '';          // full HTML reading
const to    = $('Twilio2').first().json.to;                  // WhatsApp number like 'whatsapp:+1585…'

/* 1 ▸ very light HTML → Markdown */
let text = html
  .replace(/<br\s*\/?>/gi, '\n')
  .replace(/<\/?(div|p)>/gi, '\n')
  .replace(/<h3[^>]*>(.*?)<\/h3>/gi, (m, c) => `\n*${c.trim()}*`)
  .replace(/<strong[^>]*>(.*?)<\/strong>/gi, (m, c) => `*${c.trim()}*`)
  .replace(/<li[^>]*>(.*?)<\/li>/gi,  (m, c) => `• ${c.trim()}`)
  .replace(/<\/?ul[^>]*>/gi, '\n')
  .replace(/<\/?[^>]+>/g, '')           // strip the rest
  .replace(/\n{3,}/g, '\n\n')           // collapse blank lines
  .trim();

/* 2 ▸ split into 1600-char chunks (WhatsApp limit) */
const CHUNK = 1400;
const parts = [];
while (text.length) {
  let slice = text.slice(0, CHUNK);

  /* keep whole lines: back up to last newline if possible */
  const lastNL = slice.lastIndexOf('\n');
  if (lastNL > CHUNK * 0.7) slice = slice.slice(0, lastNL);

  parts.push(slice.trim());
  text = text.slice(slice.length).trimStart();
}

/* 3 ▸ emit one item per part */
return parts.map((body, i) => ({
  json: {
    to,
    body: `(${i + 1}/${parts.length})\n${body}`,
  },
}));

