/*****************************************************************
*  Format analyst response for WhatsApp                          *
*  Handles both plain text (analyst replies) and HTML (readings)  *
*  Returns an array of {to, body} items (<=1600 chars each)      *
*****************************************************************/

const raw = $input.first().json.message.content || '';

/* ---- REPORT DUMP GUARD ---- */
/* If the AI response is over 2000 chars, it is almost certainly a report  */
/* being regurgitated, not a normal conversational reply. Suppress it.     */
/* Normal analyst responses are capped at 1200 chars by system prompt.     */
if (raw.length > 2000) {
  return [];
}
/* ---- END GUARD ---- */
const to  = $('Inbound Message').first().json.body.WaId;

/* Detect if content is HTML (has tags) or plain text */
const isHtml = /<[a-z][\s\S]*>/i.test(raw);

let text;
if (isHtml) {
  /* HTML → Markdown conversion for readings */
  text = raw
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/?(div|p)>/gi, '\n')
    .replace(/<h3[^>]*>(.*?)<\/h3>/gi, (m, c) => `\n*${c.trim()}*`)
    .replace(/<strong[^>]*>(.*?)<\/strong>/gi, (m, c) => `*${c.trim()}*`)
    .replace(/<li[^>]*>(.*?)<\/li>/gi,  (m, c) => `• ${c.trim()}`)
    .replace(/<\/?ul[^>]*>/gi, '\n')
    .replace(/<\/?[^>]+>/g, '')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
} else {
  /* Plain text — just clean up whitespace */
  text = raw.replace(/\n{3,}/g, '\n\n').trim();
}

/* Split into 1400-char chunks (WhatsApp limit) */
const CHUNK = 1400;
const parts = [];
while (text.length) {
  let slice = text.slice(0, CHUNK);
  const lastNL = slice.lastIndexOf('\n');
  if (text.length > CHUNK && lastNL > CHUNK * 0.7) slice = slice.slice(0, lastNL);
  parts.push(slice.trim());
  text = text.slice(slice.length).trimStart();
}

/* Emit one item per part — only add pagination if multiple parts */
return parts.map((body, i) => ({
  json: {
    to,
    body: parts.length > 1 ? `(${i + 1}/${parts.length})\n${body}` : body,
  },
}));

const body = $input.item.json.body || $input.item.json;
const event = body;
const eventType = event.type || '';
const obj = event.data && event.data.object ? event.data.object : {};

const PRICE_TO_TIER = {"price_1SwB6UEXsfgHNJYmo1UlBx0M":"standard","price_1SwB6UEXsfgHNJYmMJWJ7JEp":"annual","price_1SwB6VEXsfgHNJYmcvPuYRDL":"family","price_1SwB6VEXsfgHNJYmWpYkQTHo":"compatibility_bridge","price_1SwB6WEXsfgHNJYm0dlLevyw":"vocation_blueprint","price_1SwB6WEXsfgHNJYm6HYyPCuN":"child_legacy"};
const ADDON_TYPES = ['compatibility_bridge', 'vocation_blueprint', 'child_legacy'];

let result = {
  event_type: 'unknown',
  user_id: '',
  tier: 'free',
  stripe_customer_id: obj.customer || '',
  stripe_subscription_id: obj.subscription || obj.id || '',
  price_id: '',
  mode: '',
  phone: '',
  product_type: '',
  amount_cents: 0,
  data: obj
};

if (eventType === 'checkout.session.completed') {
  result.event_type = 'checkout_completed';
  result.user_id = (obj.metadata && obj.metadata.user_id) || '';
  result.phone = (obj.metadata && obj.metadata.phone) || result.user_id;
  result.mode = obj.mode || '';
  result.stripe_customer_id = obj.customer || '';
  result.stripe_subscription_id = obj.subscription || '';
  result.amount_cents = obj.amount_total || 0;

  const priceId = (obj.metadata && obj.metadata.price_id) || '';
  result.price_id = priceId;
  const tier = PRICE_TO_TIER[priceId] || 'unknown';
  result.tier = tier;
  result.product_type = ADDON_TYPES.includes(tier) ? tier : '';

} else if (eventType === 'customer.subscription.updated') {
  result.event_type = 'subscription_updated';
  result.stripe_subscription_id = obj.id || '';
  result.stripe_customer_id = obj.customer || '';
