  result.price_id = priceId;
  result.tier = PRICE_TO_TIER[priceId] || 'unknown';
  // Try to get user_id from subscription metadata
  result.user_id = (obj.metadata && obj.metadata.user_id) || '';

} else if (eventType === 'customer.subscription.deleted') {
  result.event_type = 'subscription_deleted';
  result.stripe_subscription_id = obj.id || '';
  result.stripe_customer_id = obj.customer || '';

} else if (eventType === 'invoice.payment_failed') {
  result.event_type = 'payment_failed';
  result.stripe_subscription_id = obj.subscription || '';
  result.stripe_customer_id = obj.customer || '';
}

return { json: result };

