// Parse Responses API output — comprehensive extraction
const resp = $input.first().json;
const keys = Object.keys(resp);

let textContent = '';

// Path 1: Standard Responses API — output[].type=message → content[].text
if (Array.isArray(resp.output)) {
  for (const item of resp.output) {
    if (item.type === 'message' && item.content && Array.isArray(item.content)) {
      for (const c of item.content) {
        if (c.text) textContent += c.text;
      }
    }
  }
}

// Path 2: output is a string directly
if (!textContent && typeof resp.output === 'string') {
  textContent = resp.output;
}

// Path 3: output_text at top level
if (!textContent && resp.output_text) {
  textContent = typeof resp.output_text === 'string' ? resp.output_text : JSON.stringify(resp.output_text);
}

// Path 4: choices format (fallback)
if (!textContent && resp.choices && resp.choices[0] && resp.choices[0].message) {
  textContent = resp.choices[0].message.content || '';
}

// Path 5: message.content at top level
if (!textContent && resp.message && resp.message.content) {
  textContent = resp.message.content;
}

// Path 6: find any long string value
if (!textContent) {
  for (const key of keys) {
    if (typeof resp[key] === 'string' && resp[key].length > 50) {
      textContent = resp[key];
      break;
    }
  }
}

// Hard cap: trim to last complete sentence before 1350 chars
// This prevents Code8 from splitting into (1/2)(2/2) messages
if (textContent.length > 1350) {
  const trimmed = textContent.substring(0, 1350);
  const lastPeriod = trimmed.lastIndexOf('.');
  const lastQuestion = trimmed.lastIndexOf('?');
  const lastExcl = trimmed.lastIndexOf('!');
  const cutAt = Math.max(lastPeriod, lastQuestion, lastExcl);
  if (cutAt > 800) {
    textContent = trimmed.substring(0, cutAt + 1);
  } else {
    textContent = trimmed;
  }
}

return {
  json: {
    threadId: resp.id || '',
    output: textContent,
    message: {
      content: textContent
    }
  }
};

